import numpy as np

# New algorithm description: {The 'Dynamic Clustering with Urgency Factor' algorithm leverages dynamic customer clustering with an urgency score based on the waiting time, alongside the proximity measure, to decide the next node to optimize the overall completion time.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    # Assume urgency increases with time, starting with nominal 1 for recently added customers
    urgency = np.linspace(1, 2, len(unvisited_customers))

    # Calculate dynamic clustering index
    clustering_indices = np.zeros(len(unvisited_customers))
    for i in range(len(unvisited_customers)):
        cluster_sum = 0
        for j in range(len(unvisited_customers)):
            if i != j:
                cluster_sum += np.linalg.norm(unvisited_customers[i] - unvisited_customers[j])
        clustering_indices[i] = cluster_sum

    min_score = float('inf')
    best_node = None

    for idx, customer in enumerate(unvisited_customers):
        distance_to_customer = np.linalg.norm(cur_truck_pos - customer)
        urgency_factor = urgency[idx]
        cluster_weight = 1 / (1 + clustering_indices[idx])
        score = distance_to_customer * cluster_weight * urgency_factor

        if score < min_score:
            min_score = score
            best_node = idx

    return best_node
